#include <stdio.h>
int main(){
    int T; scanf("%d", &T);
    for(int tc = 0; tc < T; ++tc){
        int code; scanf("%d", &code);
        long long a, b;
        switch(code){
            case 111:
                scanf("%lld %lld", &a, &b);
                printf("%lld\n", a + b);
                break;
            case 222:
                scanf("%lld %lld", &a, &b);
                printf("%lld\n", a - b);
                break;
            case 444:
                scanf("%lld %lld", &a, &b);
                printf("%lld\n", a * b);
                break;
            case 555:
                scanf("%lld %lld", &a, &b);
                printf("Quotient = %lld, Remainder = %lld\n", a / b, a % b);
                break;
            case 333:
                printf("Exiting\n");
                break;
            default:
                printf("Operation does not exist - please provide the correct input\n");
                break;
        }
    }
    return 0;
}

