import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if(line == null) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder out = new StringBuilder();
        for(int i = 0; i < T; i++){
            int code = Integer.parseInt(br.readLine().trim());
            long a, b;
            switch(code){
                case 111:
                    String[] add = br.readLine().trim().split(" ");
                    a = Long.parseLong(add[0]); b = Long.parseLong(add[1]);
                    out.append(a + b).append('\n');
                    break;
                case 222:
                    String[] sub = br.readLine().trim().split(" ");
                    a = Long.parseLong(sub[0]); b = Long.parseLong(sub[1]);
                    out.append(a - b).append('\n');
                    break;
                case 444:
                    String[] mul = br.readLine().trim().split(" ");
                    a = Long.parseLong(mul[0]); b = Long.parseLong(mul[1]);
                    out.append(a * b).append('\n');
                    break;
                case 555:
                    String[] div = br.readLine().trim().split(" ");
                    a = Long.parseLong(div[0]); b = Long.parseLong(div[1]);
                    out.append("Quotient = ").append(a / b).append(", Remainder = ").append(a % b).append('\n');
                    break;
                case 333:
                    out.append("Exiting\n");
                    break;
                default:
                    out.append("Operation does not exist - please provide the correct input\n");
