import sys

def solve():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    idx = 1
    out = []
    for _ in range(T):
        code = int(data[idx].strip()); idx += 1
        if code in (111, 222, 444, 555):
            a, b = map(int, data[idx].split()); idx += 1
            if code == 111:
                out.append(str(a + b))
            elif code == 222:
                out.append(str(a - b))
            elif code == 444:
                out.append(str(a * b))
            else:  # 555 division
                out.append(f"Quotient = {a // b}, Remainder = {a % b}")
        elif code == 333:
            out.append("Exiting")
        else:
            out.append("Operation does not exist - please provide the correct input")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    solve()

